<script setup>import {computed,reactive,ref,watch} from 'vue';import {useRoute} from 'vue-router';import api from '../api';const route=useRoute(),loading=ref(false),result=ref({items:[],total:0}),q=reactive({keyword:'',filter:'',page:1,size:10});const type=computed(()=>route.meta.type);const configs={users:{hint:'按昵称、手机号或用户 ID 搜索',filter:'用户状态',options:[['ACTIVE','正常'],['DISABLED','已禁用']],columns:[['id','用户 ID',100],['nickname','昵称'],['phone','手机号'],['status','状态'],['created_at','注册时间']]},pets:{hint:'按宠物名称或品种搜索',filter:'宠物类型',options:[['CAT','猫'],['DOG','狗']],columns:[['id','档案 ID',100],['name','宠物名称'],['species','类型'],['breed','品种'],['family_name','所属家庭'],['health_score','健康分'],['created_at','创建时间']]},families:{hint:'按家庭名称或成员昵称搜索',columns:[['id','家庭 ID',100],['name','家庭名称'],['owner_name','创建人'],['member_count','成员数'],['pet_count','宠物数'],['created_at','创建时间']]}};const cfg=computed(()=>configs[type.value]);async function load(){loading.value=true;try{const params={keyword:q.keyword,page:q.page,size:q.size};if(type.value==='users')params.status=q.filter;if(type.value==='pets')params.species=q.filter;result.value=await api.get('/'+type.value,{params});}finally{loading.value=false;}}function search(){q.page=1;load();}watch(type,()=>{q.keyword='';q.filter='';q.page=1;load();},{immediate:true});function display(row,key){if(key==='status')return row[key]==='ACTIVE'?'正常':row[key];if(key==='species')return row[key]==='CAT'?'猫':row[key]==='DOG'?'狗':row[key];return row[key]??'—';}</script>
<template><div><div class="list-intro"><div><p class="eyebrow">READ-ONLY DATA</p><h2>{{route.meta.title}}</h2><p>当前为只读模式，可安全查看平台业务数据。</p></div><el-tag type="info" effect="plain">只读权限</el-tag></div><article class="panel filter-panel"><el-input v-model="q.keyword" :placeholder="cfg.hint" clearable @keyup.enter="search"><template #prefix>⌕</template></el-input><el-select v-if="cfg.filter" v-model="q.filter" :placeholder="cfg.filter" clearable><el-option v-for="o in cfg.options" :key="o[0]" :label="o[1]" :value="o[0]"/></el-select><el-button type="primary" @click="search">查询</el-button><el-button @click="q.keyword='';q.filter='';search()">重置</el-button></article><article class="panel table-panel"><div class="table-title"><div><h3>数据列表</h3><span>共 {{result.total}} 条记录</span></div><span class="live"><i></i> 数据已同步</span></div><el-table v-loading="loading" :data="result.items" stripe><el-table-column v-for="c in cfg.columns" :key="c[0]" :prop="c[0]" :label="c[1]" :width="c[2]" min-width="120"><template #default="s"><el-tag v-if="c[0]==='status'" :type="s.row[c[0]]==='ACTIVE'?'success':'danger'" effect="light">{{display(s.row,c[0])}}</el-tag><b v-else-if="c[0]==='name'||c[0]==='nickname'">{{display(s.row,c[0])}}</b><span v-else>{{display(s.row,c[0])}}</span></template></el-table-column><template #empty><el-empty description="暂无符合条件的数据"/></template></el-table><div class="pagination"><el-pagination v-model:current-page="q.page" v-model:page-size="q.size" layout="total, prev, pager, next" :total="result.total" @current-change="load"/></div></article></div></template>
